class.description:
Provides an extensible Vector layer mapping [JustAMCPPrompt] abstractions. This allows clients natively routing through the MCP to list and retrieve arbitrary prompt templates safely at runtime.
[codeblock]
var prompt_exec = JustAMCPPromptExecutor.new()
var prompts = prompt_exec.list_prompts()

# Generating Prompts natively triggering auto-completion callbacks dynamically!
var ref_dict = {"name": "blazium_context"}
var arg_dict = {"name": "context_type", "value": "au"}
var result = prompt_exec.complete_prompt(ref_dict, arg_dict)
[/codeblock]
